const reg = (validate as any).ok ? await ((registerSpace as any)((validate as any).dir) as Promise<{ ok: boolean; spaceKey: string; agentSlug: string; error?: string }>) : { ok: false, spaceKey: "", agentSlug: "", error: (validate as any).errors || "validation failed" };

// The shadowed const is still poisoning the scope. `registerSpace` in this context IS the const we
